const response = $.steps.readSheet.response || {};
const values = response.values || [];
if (values.length === 0) return { dataText: 'No data found in the spreadsheet.', rowCount: 0, headers: [], columnCount: 0 };

const headers = values[0] || [];
const rows = values.slice(1);

let dataText = 'HEADERS: ' + headers.join(' | ') + '\n\n';
rows.forEach((row, i) => {
  if (i < 100) {
    dataText += 'Row ' + (i+1) + ': ';
    headers.forEach((h, hi) => {
      dataText += h + '=' + (row[hi] || '') + (hi < headers.length - 1 ? ' | ' : '');
    });
    dataText += '\n';
  }
});

if (rows.length > 100) {
  dataText += '\n... and ' + (rows.length - 100) + ' more rows (showing first 100)\n';
}

return { dataText: dataText.slice(0, 12000), rowCount: rows.length, headers, columnCount: headers.length };

const prompt = `You are a data analyst expert. Answer the following question about spreadsheet data. Be precise and data-driven in your response.

SPREADSHEET DATA (${$.steps.parseSheetData.output.rowCount} rows, ${$.steps.parseSheetData.output.columnCount} columns):
${$.steps.parseSheetData.output.dataText}

QUESTION: ${$.input.question}

INSTRUCTIONS:
- Answer the question using only the data provided
- Include specific numbers, calculations, or data points from the sheet
- If the question requires aggregation (sum, average, count, etc.), compute it
- If the question cannot be answered from the data, explain why
- Use Slack mrkdwn formatting: *bold*, _italic_, numbered lists
- Slack rules: use *bold* (NOT **bold**). No markdown tables. No # headings.
- For lists of data, use numbered lists not tables

Return ONLY valid JSON:
{
  "answer": "<detailed answer in Slack mrkdwn>",
  "dataInsights": ["<insight1>", "<insight2>"],
  "calculationsPerformed": ["<calc1>", "<calc2>"],
  "confidence": "high|medium|low",
  "rowsAnalyzed": ${$.steps.parseSheetData.output.rowCount}
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, dataInsights: [], calculationsPerformed: [], confidence: 'medium', rowsAnalyzed: 0 }; }

const ai = $.steps.parseAI.output || {};
const question = $.input.question;
const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Spreadsheet Data Answer' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 1900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answerText } });
blocks.push({ type: 'divider' });

if (ai.dataInsights && ai.dataInsights.length > 0) {
  let insightsText = '*Data Insights:*\n';
  ai.dataInsights.forEach((ins, i) => { insightsText += (i+1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insightsText.slice(0, 1900) } });
  blocks.push({ type: 'divider' });
}

if (ai.calculationsPerformed && ai.calculationsPerformed.length > 0) {
  let calcText = '*Calculations:*\n';
  ai.calculationsPerformed.forEach((c, i) => { calcText += (i+1) + '. ' + c + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: calcText.slice(0, 1900) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceEmoji + ' Confidence: *' + (ai.confidence || 'medium') + '* | Rows analyzed: *' + (ai.rowsAnalyzed || $.steps.parseSheetData.output.rowCount) + '* | Columns: *' + $.steps.parseSheetData.output.columnCount + '*' }] });

const fallback = 'Data answer for: ' + question;
return { blocks, fallback };
